package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Constructor;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseReturnsCSVParserInstance() throws Exception {
        Reader mockReader = mock(Reader.class);

        // Use reflection to create a mock CSVParser instance
        CSVParser mockParser = mock(CSVParser.class);

        // Use reflection to replace CSVParser constructor call by mocking CSVParser.parse method
        // Since CSVFormat.parse calls new CSVParser(in, this), we cannot intercept constructor with Mockito 3
        // So we create a subclass of CSVFormat that overrides parse to return our mock
        CSVFormat testFormat = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteChar(),
                csvFormat.getQuotePolicy(),
                csvFormat.getCommentStart(),
                csvFormat.getEscape(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord()) {
            @Override
            public CSVParser parse(Reader in) {
                return mockParser;
            }
        };

        CSVParser parser = testFormat.parse(mockReader);

        assertNotNull(parser);
        assertSame(mockParser, parser);
    }

    @Test
    void testParseThrowsIOException() {
        Reader mockReader = mock(Reader.class);

        // Create a CSVFormat subclass that throws IOException from parse
        CSVFormat testFormat = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteChar(),
                csvFormat.getQuotePolicy(),
                csvFormat.getCommentStart(),
                csvFormat.getEscape(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord()) {
            @Override
            public CSVParser parse(Reader in) throws IOException {
                throw new IOException("mock IO exception");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> {
            testFormat.parse(mockReader);
        });

        assertEquals("mock IO exception", thrown.getMessage());
    }
}
